export async function fetchMarketFromSeeds(
  rpc: Parameters<typeof fetchEncodedAccount>[0],
  seeds: MarketSeeds,
  config: FetchAccountConfig & { programAddress?: Address } = {},
): Promise<Account<Market>> {
  const maybeAccount = await fetchMaybeMarketFromSeeds(rpc, seeds, config);
  assertAccountExists(maybeAccount);
  return maybeAccount;
}

export async function fetchMaybeMarketFromSeeds(
  rpc: Parameters<typeof fetchEncodedAccount>[0],
  seeds: MarketSeeds,
  config: FetchAccountConfig & { programAddress?: Address } = {},
): Promise<MaybeAccount<Market>> {
  const { programAddress, ...fetchConfig } = config;
  const [address] = await findMarketPda(seeds, { programAddress });
  return await fetchMaybeMarket(rpc, address, fetchConfig);
}
